import machine
import time
import json
import ubinascii
import os
from umqtt.simple import MQTTClient

# --- Configuration ---
# Secrets should be stored in a separate config file, not hardcoded
# Create a file 'config.py' with: BROKER_IP, BROKER_PORT, MQTT_USER, MQTT_PASS, WIFI_SSID, WIFI_PASS
try:
    from config import (
        BROKER_IP,
        BROKER_PORT,
        MQTT_USER,
        MQTT_PASS,
        WIFI_SSID,
        WIFI_PASS,
        CA_CERT_PATH,
    )
except ImportError:
    raise RuntimeError("Missing config.py with broker credentials. Do not hardcode secrets.")

# --- Constants ---
TOPIC_TEMP = b"sensors/temp"
PUBLISH_INTERVAL_S = 30
MAX_RECONNECT_ATTEMPTS = 5
RECONNECT_DELAY_S = 5
TEMP_MIN_VALID = -40.0
TEMP_MAX_VALID = 125.0

# Generate a unique client ID based on device's unique ID
CLIENT_ID = b"esp32_" + ubinascii.hexlify(machine.unique_id())


def connect_wifi(ssid, password):
    """Connect to WiFi with timeout."""
    import network

    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)

    if wlan.isconnected():
        return True

    wlan.connect(ssid, password)

    timeout = 20
    while not wlan.isconnected() and timeout > 0:
        time.sleep(1)
        timeout -= 1

    if not wlan.isconnected():
        print("WiFi connection failed")
        return False

    print("WiFi connected:", wlan.ifconfig()[0])
    return True


def validate_broker_ip(ip):
    """Basic validation of broker IP address."""
    if not isinstance(ip, str) or len(ip) == 0:
        return False
    parts = ip.split(".")
    if len(parts) != 4:
        return False
    try:
        for part in parts:
            num = int(part)
            if num < 0 or num > 255:
                return False
    except ValueError:
        return False
    return True


def validate_temperature(temp):
    """Validate temperature reading is within sensor's physical range."""
    if temp is None:
        return False
    if not isinstance(temp, (int, float)):
        return False
    if temp < TEMP_MIN_VALID or temp > TEMP_MAX_VALID:
        return False
    return True


def read_temperature():
    """Read temperature from DS18B20 or internal sensor with validation."""
    try:
        # Using the internal temperature sensor (ESP32-S2/S3) or ADC-based sensor
        # For DS18B20, replace with appropriate onewire code
        import esp32
        raw_temp_f = esp32.raw_temperature()
        # Convert from Fahrenheit to Celsius
        temp_c = (raw_temp_f - 32.0) / 1.8

        if not validate_temperature(temp_c):
            print("Invalid temperature reading:", temp_c)
            return None

        return round(temp_c, 2)
    except Exception as e:
        print("Sensor read error:", e)
        return None


def create_mqtt_client():
    """Create MQTT client with TLS and authentication."""
    if not validate_broker_ip(BROKER_IP):
        raise ValueError("Invalid broker IP address")

    if not MQTT_USER or not MQTT_PASS:
        raise ValueError("MQTT credentials must not be empty")

    ssl_params = {}
    # Load CA certificate for TLS verification if available
    try:
        with open(CA_CERT_PATH, "rb") as f:
            ca_cert = f.read()
        ssl_params = {"ca_certs": ca_cert, "cert_reqs": True}
    except OSError:
        # If no CA cert file, still use TLS but log warning
        print("WARNING: No CA cert found, using TLS without server verification")
        ssl_params = {"cert_reqs": False}

    client = MQTTClient(
        CLIENT_ID,
        BROKER_IP,
        port=BROKER_PORT,
        user=MQTT_USER,
        password=MQTT_PASS,
        keepalive=60,
        ssl=True,
        ssl_params=ssl_params,
    )

    return client


def connect_mqtt(client):
    """Connect to MQTT broker with retry logic."""
    for attempt in range(MAX_RECONNECT_ATTEMPTS):
        try:
            client.connect()
            print("MQTT connected to broker")
            return True
        except Exception as e:
            print("MQTT connect attempt {}/{} failed: {}".format(
                attempt + 1, MAX_RECONNECT_ATTEMPTS, e
            ))
            time.sleep(RECONNECT_DELAY_S)

    print("Failed to connect to MQTT broker after all attempts")
    return False


def publish_temperature(client, temperature):
    """Publish validated temperature data as JSON."""
    payload = json.dumps({
        "device_id": CLIENT_ID.decode(),
        "temperature_c": temperature,
        "timestamp": time.time(),
    })

    client.publish(TOPIC_TEMP, payload.encode(), qos=1)
    print("Published: {} to {}".format(payload, TOPIC_TEMP))


def main():
    """Main loop: connect and publish sensor data."""
    # Connect to WiFi
    if not connect_wifi(WIFI_SSID, WIFI_PASS):
        print("Cannot proceed without WiFi")
        machine.reset()

    # Create and connect MQTT client
    client = create_mqtt_client()

    if not connect_mqtt(client):
        print("Cannot proceed without MQTT connection")
        machine.reset()

    consecutive_failures = 0

    try:
        while True:
            try:
                # Read and validate temperature
                temp = read_temperature()

                if temp is not None:
                    publish_temperature(client, temp)
                    consecutive_failures = 0
                else:
                    print("Skipping publish due to invalid reading")

                # Ping to keep connection alive
                client.ping()

            except OSError as e:
                print("Connection error:", e)
                consecutive_failures += 1

                if consecutive_failures >= MAX_RECONNECT_ATTEMPTS:
                    print("Too many failures, resetting device")
                    machine.reset()

                # Attempt reconnection
                try:
                    client.disconnect()
                except Exception:
                    pass

                time.sleep(RECONNECT_DELAY_S)

                if not connect_mqtt(client):
                    print("Reconnection failed")
                    continue

            time.sleep(PUBLISH_INTERVAL_S)

    except KeyboardInterrupt:
        print("Shutting down")
    finally:
        try:
            client.disconnect()
        except Exception:
            pass
        print("Disconnected from MQTT broker")


if __name__ == "__main__":
    main()